async function fetchWithRetry(url, options = {}, maxRetries = 3) {
  const timeoutMs = options.timeout || 10000;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), timeoutMs);
      const mergedOptions = { ...options, signal: controller.signal };
      delete mergedOptions.timeout;
      const response = await fetch(url, mergedOptions);
      clearTimeout(timeout);

      if (response.ok || response.status < 500) {
        return response;
      }

      if (attempt < maxRetries) {
        if (attempt === 0 && typeof showReconnectNotice === 'function') {
          showReconnectNotice();
        }
        await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, attempt)));
      } else {
        return response;
      }
    } catch (error) {
      if (attempt === maxRetries) throw error;
      if (attempt === 0 && typeof showReconnectNotice === 'function') {
        showReconnectNotice();
      }
      await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, attempt)));
    }
  }
}

function showReconnectNotice() {
  let banner = document.getElementById('reconnect-banner');
  if (!banner) {
    banner = document.createElement('div');
    banner.id = 'reconnect-banner';
    banner.setAttribute('role', 'status');
    banner.setAttribute('aria-live', 'polite');
    banner.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:100;padding:10px 16px;background:rgba(245,158,11,0.9);color:#000;text-align:center;font-weight:700;';
    banner.textContent = 'Tentative de reconnexion...';
    document.body.prepend(banner);
  }
}

function hideReconnectNotice() {
  const banner = document.getElementById('reconnect-banner');
  if (banner) banner.remove();
}

if (typeof window !== 'undefined') {
  window.fetchWithRetry = fetchWithRetry;
  window.showReconnectNotice = showReconnectNotice;
  window.hideReconnectNotice = hideReconnectNotice;
}

const panelConfig = window.__CLOUD_PANEL_CONFIG__ || {};

const state = {
  publicPrefix: String(panelConfig.publicPrefix || "/cloud-panel").replace(/\/$/, ""),
  csrfToken: "",
  currentPath: "",
  files: [],
  diskUsed: "",
  diskTotal: "",
  diskPercent: 0,
  pageSize: 50,
  page: 1,
  renameTarget: null,
  deleteTarget: null,
  uploadQueue: [],
};

const els = {
  breadcrumb: document.querySelector("#breadcrumb"),
  diskStrip: document.querySelector("#diskStrip"),
  diskUsed: document.querySelector("#diskUsed"),
  diskFill: document.querySelector("#diskFill"),
  diskTotal: document.querySelector("#diskTotal"),
  fileList: document.querySelector("#fileList"),
  pagination: document.querySelector("#pagination"),
  pageInfo: document.querySelector("#pageInfo"),
  alert: document.querySelector("#alert"),
  alertText: document.querySelector("#alertText"),
  retryButton: document.querySelector("#retryButton"),
  toast: document.querySelector("#toast"),
  uploadButton: document.querySelector("#uploadButton"),
  mkdirButton: document.querySelector("#mkdirButton"),
  refreshButton: document.querySelector("#refreshButton"),
  uploadDialog: document.querySelector("#uploadDialog"),
  uploadZone: document.querySelector("#uploadZone"),
  fileInput: document.querySelector("#fileInput"),
  uploadProgress: document.querySelector("#uploadProgress"),
  uploadMessage: document.querySelector("#uploadMessage"),
  cancelUploadButton: document.querySelector("#cancelUploadButton"),
  mkdirDialog: document.querySelector("#mkdirDialog"),
  mkdirNameInput: document.querySelector("#mkdirNameInput"),
  mkdirMessage: document.querySelector("#mkdirMessage"),
  cancelMkdirButton: document.querySelector("#cancelMkdirButton"),
  confirmMkdirButton: document.querySelector("#confirmMkdirButton"),
  renameDialog: document.querySelector("#renameDialog"),
  renameInput: document.querySelector("#renameInput"),
  renameMessage: document.querySelector("#renameMessage"),
  cancelRenameButton: document.querySelector("#cancelRenameButton"),
  confirmRenameButton: document.querySelector("#confirmRenameButton"),
  deleteDialog: document.querySelector("#deleteDialog"),
  deleteName: document.querySelector("#deleteName"),
  cancelDeleteButton: document.querySelector("#cancelDeleteButton"),
  confirmDeleteButton: document.querySelector("#confirmDeleteButton"),
};

function route(path) {
  if (path === "/") return `${state.publicPrefix || ""}/`;
  return `${state.publicPrefix}${path.startsWith("/") ? path : `/${path}`}`;
}

function apiUrl(path) {
  return route(`/api${path}`);
}

async function api(path, options = {}, retryCsrf = true) {
  const headers = new Headers(options.headers || {});
  headers.set("Accept", "application/json");
  const isFormData = options.body instanceof FormData;
  if (options.body && !isFormData && !headers.has("Content-Type")) headers.set("Content-Type", "application/json");
  if ((options.method || "GET").toUpperCase() !== "GET") headers.set("X-Cloud-Panel-CSRF", state.csrfToken);

  const response = await fetchWithRetry(path, { ...options, headers, credentials: "same-origin" });
  const payload = await response.json().catch(() => ({}));
  if (response.ok) return payload;

  const detail = typeof payload.detail === "object" && payload.detail ? payload.detail : {};
  const error = new Error(detail.message || payload.detail || "Action impossible.");
  error.code = detail.code || `http_${response.status}`;
  error.recovery = detail.recovery || "Réessayer";
  error.status = response.status;
  if (response.status === 403 && error.code === "csrf_expired" && retryCsrf) {
    await refreshSession();
    return api(path, options, false);
  }
  throw error;
}

async function refreshSession() {
  const session = await api(apiUrl("/session"), { cache: "no-store" }, false);
  state.csrfToken = session.csrfToken;
}

async function loadFiles(path) {
  try {
    const data = await api(apiUrl(`/files?path=${encodeURIComponent(path)}`));
    state.currentPath = data.current_path || "";
    state.files = data.items || [];
    state.diskUsed = data.disk_used || "";
    state.diskTotal = data.disk_total || "";
    state.diskPercent = data.disk_percent || 0;
    state.page = 1;
    render();
  } catch (error) {
    showError(error);
  }
}

function renderBreadcrumb() {
  const parts = state.currentPath ? state.currentPath.replace(/\\/g, "/").split("/").filter(Boolean) : [];
  els.breadcrumb.replaceChildren();

  const rootLink = document.createElement("a");
  rootLink.href = "#";
  rootLink.dataset.path = "";
  rootLink.textContent = "Cloud Panel";
  rootLink.addEventListener("click", (e) => { e.preventDefault(); navigate(""); });
  els.breadcrumb.append(rootLink);

  let accumulated = "";
  for (const part of parts) {
    const sep = document.createElement("span");
    sep.className = "separator";
    sep.textContent = "/";
    els.breadcrumb.append(sep);

    accumulated = accumulated ? `${accumulated}/${part}` : part;
    const link = document.createElement("a");
    link.href = "#";
    link.dataset.path = accumulated;
    link.textContent = part;
    link.addEventListener("click", (e) => { e.preventDefault(); navigate(accumulated); });
    els.breadcrumb.append(link);
  }
}

function renderDisk() {
  if (state.diskTotal && state.diskTotal !== "N/A") {
    els.diskStrip.hidden = false;
    els.diskUsed.textContent = state.diskUsed;
    els.diskTotal.textContent = state.diskTotal;
    const pct = Math.min(100, Math.max(0, state.diskPercent));
    els.diskFill.style.width = `${pct}%`;
    els.diskFill.className = "disk-fill" + (pct > 90 ? " critical" : pct > 75 ? " warn" : " ok");
  } else {
    els.diskStrip.hidden = true;
  }
}

function renderPagination() {
  const totalPages = Math.max(1, Math.ceil(state.files.length / state.pageSize));
  els.pageInfo.textContent = `Page ${state.page} / ${totalPages} · ${state.files.length} élément(s)`;
  els.pagination.hidden = state.files.length === 0;
}

function getPageItems() {
  const start = (state.page - 1) * state.pageSize;
  return state.files.slice(start, start + state.pageSize);
}

function formatDate(ts) {
  const value = Number(ts);
  if (!Number.isFinite(value) || value <= 0) return "";
  return new Date(value * 1000).toLocaleString("fr-FR", { dateStyle: "short", timeStyle: "short" });
}

function formatBytes(value) {
  const bytes = Number(value) || 0;
  if (bytes === 0) return "0 o";
  const units = ["o", "Ko", "Mo", "Go", "To"];
  const index = Math.min(Math.floor(Math.log(Math.abs(bytes)) / Math.log(1024)), units.length - 1);
  return `${(bytes / 1024 ** index).toFixed(index === 0 ? 0 : 1)} ${units[index]}`;
}

function renderFiles() {
  const items = getPageItems();

  if (items.length === 0) {
    els.fileList.replaceChildren(
      Object.assign(document.createElement("div"), {
        className: "empty-state",
        innerHTML: '<div class="empty-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M8.5 18.25h8.25a3.25 3.25 0 0 0 .6-6.44A4.75 4.75 0 0 0 8 10.5a3.5 3.5 0 0 0 .5 6.94Z"/></svg></div><p>Ce dossier est vide.</p>',
      })
    );
    return;
  }

  els.fileList.replaceChildren(
    ...items.map((file) => {
      const row = document.createElement("div");
      row.className = "file-item";

      const info = document.createElement("div");
      info.className = "file-info";

      const icon = document.createElement("span");
      icon.className = `file-icon${file.is_dir ? " folder" : ""}`;
      icon.setAttribute("aria-hidden", "true");
      icon.innerHTML = file.is_dir
        ? '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M3.75 6.75a2 2 0 0 1 2-2H10l2 2.5h6.25a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2H5.75a2 2 0 0 1-2-2z"/></svg>'
        : '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M7.75 3.75h4.5l6 6v10.5a1 1 0 0 1-1 1H7.75a1 1 0 0 1-1-1V4.75a1 1 0 0 1 1-1z"/><path d="M12.25 3.75v6h6"/></svg>';
      info.append(icon);

      const name = document.createElement("span");
      name.className = `file-name${file.is_dir ? " dir" : ""}`;
      name.textContent = file.name;
      name.title = file.name;
      if (file.is_dir) {
        name.addEventListener("click", () => navigate(file.path));
      }
      info.append(name);
      row.append(info);

      const meta = document.createElement("div");
      meta.className = "file-meta";
      if (file.size) {
        meta.append(Object.assign(document.createElement("span"), { textContent: file.size }));
      }
      if (file.modified) {
        meta.append(Object.assign(document.createElement("span"), { textContent: formatDate(file.modified) }));
      }
      row.append(meta);

      const actions = document.createElement("div");
      actions.className = "file-actions";

      if (!file.is_dir) {
        const downloadBtn = document.createElement("a");
        downloadBtn.className = "icon-action";
        downloadBtn.href = apiUrl(`/files/download?path=${encodeURIComponent(file.path)}`);
        downloadBtn.setAttribute("aria-label", `Télécharger ${file.name}`);
        downloadBtn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 4v10m0 0 3.5-3.5M12 14l-3.5-3.5M5 18.25h14"/></svg>';
        actions.append(downloadBtn);
      }

      const renameBtn = document.createElement("button");
      renameBtn.className = "icon-action";
      renameBtn.setAttribute("aria-label", `Renommer ${file.name}`);
      renameBtn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2"><path d="M15.25 5.25 18.75 8.75M7.75 16.25l-1 2 2-1L16 10 14 8Z"/></svg>';
      renameBtn.addEventListener("click", () => openRenameDialog(file));
      actions.append(renameBtn);

      const deleteBtn = document.createElement("button");
      deleteBtn.className = "icon-action danger";
      deleteBtn.setAttribute("aria-label", `Supprimer ${file.name}`);
      deleteBtn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2"><path d="M5 7.75h14M9 7.75V5.5a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2.25M19 7.75v11a1.5 1.5 0 0 1-1.5 1.5H6.5A1.5 1.5 0 0 1 5 18.75V7.75"/></svg>';
      deleteBtn.addEventListener("click", () => openDeleteDialog(file));
      actions.append(deleteBtn);

      row.append(actions);
      return row;
    })
  );
}

function render() {
  renderBreadcrumb();
  renderDisk();
  renderFiles();
  renderPagination();
}

function navigate(path) {
  state.currentPath = path;
  loadFiles(path);
  updateUrl();
}

function showToast(message) {
  els.toast.textContent = message;
  els.toast.hidden = false;
  window.clearTimeout(showToast.timer);
  showToast.timer = window.setTimeout(() => {
    els.toast.hidden = true;
  }, 4200);
}

function showError(error) {
  els.alertText.textContent = error?.message || "Action impossible.";
  els.alert.hidden = false;
}

function clearError() {
  els.alert.hidden = true;
  els.alertText.textContent = "";
}

// ── Session ──

async function initSession() {
  try {
    const result = await api(apiUrl("/session"), { cache: "no-store" }, false);
    state.csrfToken = result.csrfToken;
  } catch {
    // continue
  }
}

// ── Upload ──

function setupUploadZone() {
  els.uploadZone.addEventListener("click", () => els.fileInput.click());

  els.uploadZone.addEventListener("dragover", (e) => {
    e.preventDefault();
    els.uploadZone.classList.add("dragover");
  });

  els.uploadZone.addEventListener("dragleave", () => {
    els.uploadZone.classList.remove("dragover");
  });

  els.uploadZone.addEventListener("drop", (e) => {
    e.preventDefault();
    els.uploadZone.classList.remove("dragover");
    if (e.dataTransfer.files.length) {
      startUpload(e.dataTransfer.files);
    }
  });

  els.fileInput.addEventListener("change", () => {
    if (els.fileInput.files.length) {
      startUpload(els.fileInput.files);
      els.fileInput.value = "";
    }
  });
}

async function startUpload(files) {
  els.uploadMessage.textContent = "";
  els.uploadMessage.className = "field-message";
  els.uploadProgress.hidden = false;
  els.uploadProgress.replaceChildren(
    ...Array.from(files).map((file) => {
      const row = document.createElement("div");
      row.className = "progress-row";
      row.dataset.filename = file.name;

      const name = document.createElement("span");
      name.className = "progress-name";
      name.textContent = file.name;
      row.append(name);

      const track = document.createElement("div");
      track.className = "progress-track";
      const fill = document.createElement("div");
      fill.className = "progress-fill";
      fill.style.width = "0%";
      track.append(fill);
      row.append(track);

      const status = document.createElement("span");
      status.className = "progress-status";
      status.textContent = "0%";
      row.append(status);

      return row;
    })
  );

  for (const file of files) {
    await uploadSingleFile(file);
  }

  showToast("Upload termine.");
  loadFiles(state.currentPath);
}

async function uploadSingleFile(file) {
  const formData = new FormData();
  formData.append("path", state.currentPath);
  formData.append("file", file);

  try {
    const xhr = new XMLHttpRequest();
    xhr.open("POST", apiUrl("/files/upload"));
    xhr.setRequestHeader("X-Cloud-Panel-CSRF", state.csrfToken);

    const progressRow = els.uploadProgress.querySelector(`[data-filename="${file.name}"]`);
    const fill = progressRow?.querySelector(".progress-fill");
    const status = progressRow?.querySelector(".progress-status");

    xhr.upload.addEventListener("progress", (e) => {
      if (e.lengthComputable && fill && status) {
        const pct = Math.round((e.loaded / e.total) * 100);
        fill.style.width = `${pct}%`;
        status.textContent = `${pct}%`;
      }
    });

    await new Promise((resolve, reject) => {
      xhr.onload = () => {
        if (xhr.status >= 200 && xhr.status < 300) resolve();
        else reject(new Error("Upload echoue"));
      };
      xhr.onerror = () => reject(new Error("Erreur reseau"));
      xhr.send(formData);
    });
  } catch (error) {
    showError(error);
  }
}

// ── Mkdir ──

function openMkdirDialog() {
  els.mkdirNameInput.value = "";
  els.mkdirMessage.textContent = "";
  els.mkdirDialog.showModal();
}

els.mkdirDialog.querySelector("form").addEventListener("submit", (e) => {
  e.preventDefault();
  els.confirmMkdirButton.click();
});

els.confirmMkdirButton.addEventListener("click", async () => {
  const name = els.mkdirNameInput.value.trim();
  if (!name) {
    els.mkdirMessage.textContent = "Le nom est requis.";
    els.mkdirMessage.className = "field-message error";
    return;
  }

  try {
    const formData = new FormData();
    formData.append("path", state.currentPath);
    formData.append("name", name);
    const result = await api(apiUrl("/files/mkdir"), { method: "POST", body: formData });
    showToast(`Dossier "${result.name}" cree.`);
    els.mkdirDialog.close();
    loadFiles(state.currentPath);
  } catch (error) {
    els.mkdirMessage.textContent = error.message;
    els.mkdirMessage.className = "field-message error";
  }
});

els.cancelMkdirButton.addEventListener("click", () => els.mkdirDialog.close());

// ── Rename ──

function openRenameDialog(file) {
  state.renameTarget = file;
  els.renameInput.value = file.name;
  els.renameMessage.textContent = "";
  els.renameDialog.showModal();
}

els.renameDialog.querySelector("form").addEventListener("submit", (e) => {
  e.preventDefault();
  els.confirmRenameButton.click();
});

els.confirmRenameButton.addEventListener("click", async () => {
  const newName = els.renameInput.value.trim();
  if (!newName || !state.renameTarget) return;

  try {
    const formData = new FormData();
    formData.append("path", state.currentPath);
    formData.append("old_name", state.renameTarget.name);
    formData.append("new_name", newName);
    const result = await api(apiUrl("/files/rename"), { method: "POST", body: formData });
    showToast(`"${result.old_name}" renomme en "${result.new_name}".`);
    els.renameDialog.close();
    state.renameTarget = null;
    loadFiles(state.currentPath);
  } catch (error) {
    els.renameMessage.textContent = error.message;
    els.renameMessage.className = "field-message error";
  }
});

els.cancelRenameButton.addEventListener("click", () => { els.renameDialog.close(); state.renameTarget = null; });

// ── Delete ──

function openDeleteDialog(file) {
  state.deleteTarget = file;
  els.deleteName.textContent = file.name;
  els.deleteDialog.showModal();
}

els.deleteDialog.querySelector("form").addEventListener("submit", (e) => {
  e.preventDefault();
  els.confirmDeleteButton.click();
});

els.confirmDeleteButton.addEventListener("click", async () => {
  if (!state.deleteTarget) return;

  try {
    const formData = new FormData();
    formData.append("path", state.currentPath);
    formData.append("name", state.deleteTarget.name);
    const result = await api(apiUrl("/files/delete"), { method: "POST", body: formData });
    showToast(`"${result.name}" supprime.`);
    els.deleteDialog.close();
    state.deleteTarget = null;
    loadFiles(state.currentPath);
  } catch (error) {
    showError(error);
  }
});

els.cancelDeleteButton.addEventListener("click", () => { els.deleteDialog.close(); state.deleteTarget = null; });

// ── Events ──

els.uploadButton.addEventListener("click", () => els.uploadDialog.showModal());
els.cancelUploadButton.addEventListener("click", () => {
  els.uploadDialog.close();
  els.uploadProgress.hidden = true;
});

els.mkdirButton.addEventListener("click", openMkdirDialog);

els.refreshButton.addEventListener("click", async () => {
  try {
    await api(apiUrl("/files/refresh"), { method: "POST" });
    showToast("Cache vide.");
    loadFiles(state.currentPath);
  } catch (error) {
    showError(error);
  }
});

els.retryButton.addEventListener("click", () => {
  clearError();
  loadFiles(state.currentPath);
});

// ── URL sync ──

function updateUrl() {
  const url = new URL(window.location.href);
  if (state.currentPath) url.searchParams.set("path", state.currentPath);
  else url.searchParams.delete("path");
  window.history.replaceState({}, "", url.toString());
}

function applyUrlState() {
  const url = new URL(window.location.href);
  return url.searchParams.get("path") || "";
}

// ── Init ──

async function init() {
  setupUploadZone();
  const initialPath = applyUrlState();
  await initSession();
  await loadFiles(initialPath);
}

init();
